import{_ as l}from"./nyalra_kb-7135827b.js";import{_ as p}from"./nyalra_no_mono-8344e451.js";import{_ as s,W as c,X as _,Y as i,Z as e,$ as t,a1 as a,a2 as m,a0 as d,C as o}from"./framework-91490e6a.js";const u={},f=e("figure",null,[e("img",{src:l,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/8bccf239c51d79ad71baa4d18a2a3069.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),b=d('<hr><p>在十几岁的时候，受到美少女游戏的影响，我对美少女角色着迷不已。</p><p>当时我也喜欢特摄、机器人动画等，但我认为最重要的还是美少女。我认为大概是「美少女角色占60%：其他（包括生活）占40%」的比例。</p><p>现在情况变成了「美少女角色占20%：特摄·实景电影占80%」。我注意到自己不知不觉地追赶着未曾观看过的昭和特摄，沉迷于观看实景电影。不知何时开始，购买的立体物品也更多地是超怪兽和机械玩具，直到比起美少女手办，房间里更多地被怪兽和特摄玩具填满，我才终于开始发觉这一切。</p><p>简单来说，作为我接下来的兴趣，我正体会到在实景影片中的映像表达。这不再是完全自由的动画，而是使用真实的风景和人物，受到巨大限制的实景影片。追求美到何种程度、过去拍摄名作的导演是如何表达的，我通过自己的眼睛亲身体验到这一切，这使我感到愉悦！如果其中还有巨大的怪兽或奥特曼登场并展开激战……那会更令人高兴！所以，我开始更加沉迷地欣赏特摄和电影，花费更多时间在这方面。</p><p>我心中的美少女形象，曾经一度在「超天酱」这个角色中得到了彻底表达，因此我对美少女的兴趣似乎突然间消失了。对于超天酱……确切地说，小雨的描绘，如果用一种非常夸张的说法，是想要表现出「超越恶劣性格之外的可爱和美丽」。这种情感的起源可以追溯到坂口安吾的『夜长姬与耳男』。然而，在对夜长姬进行现代解释的过程中，受到了太多亚文化、复杂情结和互联网文化的影响，最终成为一个角色，已经无法辨认出原型。好吧，算了。无论如何，通过这个过程找到一个我对于「美少女角色」的答案，我感觉嗯，也许暂时可以不再关心美少女角色了！就是像这样的倦怠感。</p><p>而且，还有一件事情或许更为重要。我开始考虑：「当我和这个美少女角色并排站在一起时，这段关系是否能在现实中持续下去呢？」</p><p>首先，大多数美少女角色与我年龄相差较大，仅仅因为这一点在现实中就显得有犯罪倾向，而且在话题和兴趣上可能也合不来……这让我感到不安。我从以前就开始重复观看特摄和机器人动画，算是那种被称为「麻烦的宅男」的类型，如果再加上年龄差异，话题和生活方式几乎不可能一致。显然，对方如果迎合我，很可能会感到疲惫不堪。而且，我从来没有打算将我的生活方式迎合女主角。我想在喜欢的时候读书，想在喜欢的时候看电影……。</p><p>此外，考虑到年龄，结婚也应该纳入考虑范围，到那时还有工作、金钱、搬家等等，我不禁想象一些真实的事情。为什么呢？我自己也不知道。肯定是因为从现在开始，必须花时间在各种连载和企划上，想象与恋人相处的时间，实际上有点难以实现。每个人都会在不知不觉中，对「美少女动画的女主角」产生杏欲，而且相比人妻反而更能让人感受到现实感。所以，美少女动画们也通过将女主角设计成胸部丰满的「妈妈」，满足了需求。这就是需求和供应。虽然我还没有到那个年龄。</p><p>随着年龄的增长，现实显得更加复杂。 有一系列事情都不是「爱」或「恋」所能解决的。...... 不，我从来没有过男女同居的经历，所以我也不可能知道其中的艰辛。</p><p>说实话，即便在十几岁或二十前几岁的时候，那时候同样存在着「没有钱」、「没有工作」的种种障碍！那么，为什么年轻时我能够想象「与这个女孩一同漫步」的情景呢？直截了当地说，这是因为那时的我，拥有着无需理由的自信，正是年轻本身，正是因为有了「爱」。那么，现在的我是不是失去了爱呢？尽管对于对爱的探索和感性并没有减退的感觉。那么它到底去了哪里呢……一想到这里，啊，或许是巨兽和英雄……使我超越了「年轻」，年轻溢出了，反而回到了「童心」中，我非常深切地认为是这样的。</p><hr><p><img src="'+p+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/8a7a41d949f8c070167152e61a43877b.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【毒蛛神】最新一期的战队中新增的战士以塔兰图拉毒蛛为原型，相关的玩具也都充满了这样炫酷的蜘蛛元素。真是太棒了！这个God Tarantula，翻转后可以像扭蛋玩具一样操控，变形成为一只修长的两条腿的机器人，就像变形金刚一样。但是，我对于那个形态并不太感兴趣，因此我将其放在桌子上，欣赏那只巨大的白色蜘蛛。</p></blockquote>',14);function g(x,y){const n=o("ExternalLinkIcon"),r=o("RouterLink");return c(),_("div",null,[i(" more "),f,e("p",null,[t("原文链接："),e("a",h,[t("第40回／失せる美少女キャラクターへの興味"),a(n)])]),e("blockquote",null,[k,e("p",null,[a(r,{to:"/posts/Translate/nyalra_kb_39.html"},{default:m(()=>[t("【奈亚拉面壁自语】第39回｜不可容忍之物【230815】")]),_:1})])]),b])}const C=s(u,[["render",g],["__file","nyalra_kb_40.html.vue"]]);export{C as default};
